          "description": "Target lives under one of the commit-bucket Segment anchors.",
          "type": "string"
        }
      ]
    },
    "DeliveryMode": {
      "description": "Derived routing decision computed by the merge phase from\n`consensus_breaking` + `poc_implementable`. Drives Phase 5 publishing.",
      "oneOf": [
        {
          "const": "normal_pr",
